import random
from typing import List, Tuple, Any, Union, Optional

# Edge can be unweighted (u, v) or weighted (u, v, w
Edge = Union[Tuple[Any, Any], Tuple[Any, Any, Any]]

def generate_random_node_from_edge_list(edge_list: List[Edge]) -> Optional[Any]:
    nodes = set()
    for edge in edge_list:
        if len(edge) >= 2:
            u, v = edge[0], edge[1]
            if u is not None:
                nodes.add(u)
            if v is not None:
                nodes.add(v)

    nodes = list(nodes)
    if not nodes:
        return None  # no nodes at all

    return random.choice(nodes)```

