import random
from typing import List, Tuple, Any, Union

# Edge can be unweighted (u, v) or weighted (u, v, w)
Edge = Union[Tuple[Any, Any], Tuple[Any, Any, Any]]

def generate_shortest_path_length_sample_from_edge_list(edge_list: List[Edge]) -> Tuple[Any, Any]:
    nodes = set()
    for edge in edge_list:
        if len(edge) >= 2:
            u, v = edge[0], edge[1]
            if u is not None:
                nodes.add(u)
            if v is not None:
                nodes.add(v)

    nodes = list(nodes)
    if len(nodes) == 0:
        return None, None
    if len(nodes) == 1:
        return nodes[0], nodes[0]

    # Pick two distinct random nodes
    return tuple(random.sample(nodes, 2))
```

